import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import heroImage from '../assets/images/png13.jpg';

const Hero = () => {
    const { t } = useTranslation();
    const [isVisible, setIsVisible] = useState(false);
    const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

    useEffect(() => {
        const timer = setTimeout(() => {
            setIsVisible(true);
        }, 100);

        // Mouse movement for parallax effect
        const handleMouseMove = (e) => {
            setMousePosition({
                x: (e.clientX / window.innerWidth) * 100,
                y: (e.clientY / window.innerHeight) * 100
            });
        };

        window.addEventListener('mousemove', handleMouseMove);

        // Create floating elements
        const createFloatingElements = () => {
            const heroSection = document.querySelector('.hero-container');
            if (!heroSection) return;

            // Create floating particles with lighter colors
            for (let i = 0; i < 20; i++) {
                const particle = document.createElement('div');
                particle.className = 'floating-particle';
                particle.style.cssText = `
                    position: absolute;
                    width: ${Math.random() * 8 + 4}px;
                    height: ${Math.random() * 8 + 4}px;
                    background: linear-gradient(45deg, #60a5fa, #a78bfa, #f472b6);
                    border-radius: 50%;
                    left: ${Math.random() * 100}%;
                    top: ${Math.random() * 100}%;
                    opacity: ${Math.random() * 0.8 + 0.4};
                    animation: float ${Math.random() * 3 + 2}s ease-in-out infinite alternate;
                    z-index: 1;
                    box-shadow: 0 0 20px rgba(96, 165, 250, 0.6);
                `;
                heroSection.appendChild(particle);
            }

            // Create geometric shapes with lighter colors
            for (let i = 0; i < 8; i++) {
                const shape = document.createElement('div');
                shape.className = 'floating-shape';
                const isCircle = Math.random() > 0.5;
                shape.style.cssText = `
                    position: absolute;
                    width: ${Math.random() * 60 + 40}px;
                    height: ${Math.random() * 60 + 40}px;
                    background: linear-gradient(135deg, rgba(96, 165, 250, 0.3), rgba(167, 139, 250, 0.3));
                    border: 2px solid rgba(96, 165, 250, 0.6);
                    ${isCircle ? 'border-radius: 50%;' : 'border-radius: 12px; transform: rotate(45deg);'}
                    left: ${Math.random() * 100}%;
                    top: ${Math.random() * 100}%;
                    animation: float ${Math.random() * 4 + 3}s ease-in-out infinite alternate;
                    z-index: 1;
                    box-shadow: 0 0 15px rgba(96, 165, 250, 0.4);
                `;
                heroSection.appendChild(shape);
            }
        };

        // Add CSS animations
        const style = document.createElement('style');
        style.textContent = `
            @keyframes float {
                0% { transform: translateY(0px) translateX(0px) rotate(0deg); }
                100% { transform: translateY(-20px) translateX(10px) rotate(10deg); }
            }
            @keyframes pulse-glow {
                0%, 100% { box-shadow: 0 0 30px rgba(96, 165, 250, 0.5); }
                50% { box-shadow: 0 0 50px rgba(167, 139, 250, 0.8); }
            }
            @keyframes gradient-shift {
                0% { background-position: 0% 50%; }
                50% { background-position: 100% 50%; }
                100% { background-position: 0% 50%; }
            }
        `;
        document.head.appendChild(style);

        createFloatingElements();

        return () => {
            clearTimeout(timer);
            window.removeEventListener('mousemove', handleMouseMove);
            document.head.removeChild(style);
        };
    }, []);

    return (
        <section className="relative min-h-screen bg-gradient-to-br from-blue-50 via-indigo-100 to-purple-100 overflow-hidden">
            {/* Background Elements */}
            <div className="hero-container absolute inset-0"></div>

            {/* Animated Background Gradient */}
            <div 
                className="absolute inset-0 opacity-40"
                style={{
                    background: `radial-gradient(circle at ${mousePosition.x}% ${mousePosition.y}%, rgba(96, 165, 250, 0.4) 0%, rgba(167, 139, 250, 0.3) 30%, transparent 60%)`
                }}
            ></div>

            {/* Grid Pattern */}
            <div className="absolute inset-0 opacity-20">
                <div className="absolute inset-0" style={{
                    backgroundImage: `linear-gradient(rgba(96, 165, 250, 0.4) 1px, transparent 1px),
                                     linear-gradient(90deg, rgba(96, 165, 250, 0.4) 1px, transparent 1px)`,
                    backgroundSize: '50px 50px'
                }}></div>
            </div>

            <div className="relative z-10 container mx-auto px-6 lg:px-8 pt-20 pb-16">
                <div className="flex flex-col lg:flex-row items-center justify-between min-h-screen">

                    {/* Left Content */}
                    <div className={`lg:w-1/2 space-y-8 transform transition-all duration-1000 ${isVisible ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>

                        {/* Badge */}
                        <div className="inline-flex items-center px-6 py-3 bg-gradient-to-r from-blue-100 to-purple-100 border-2 border-blue-300 rounded-full backdrop-blur-sm shadow-lg">
                            <div className="w-3 h-3 bg-green-400 rounded-full mr-3 animate-pulse shadow-lg"></div>
                            <span className="text-blue-700 text-sm font-semibold">
                                🚀 Now Enrolling for 2024
                            </span>
                        </div>

                        {/* Main Title */}
                        <div className="space-y-4">
                            <h1 className="text-5xl lg:text-7xl font-black leading-tight">
                                <span className="bg-gradient-to-r from-gray-800 via-blue-600 to-purple-600 bg-clip-text text-transparent">
                                    {t('hero.title.line1')}
                                </span>
                                <br />
                                <span className="relative inline-block">
                                    <span className="bg-gradient-to-r from-blue-500 via-purple-500 to-pink-500 bg-clip-text text-transparent animate-pulse">
                                        {t('hero.title.highlight')}
                                    </span>
                                    <div className="absolute -inset-1 bg-gradient-to-r from-blue-400 to-purple-400 blur-xl opacity-40 animate-pulse"></div>
                                </span>
                                <span className="bg-gradient-to-r from-gray-800 via-blue-600 to-purple-600 bg-clip-text text-transparent">
                                    {' '}{t('hero.title.line2')}
                                </span>
                            </h1>
                        </div>

                        {/* Description */}
                        <p className="text-xl text-gray-600 leading-relaxed font-medium max-w-xl">
                            {t('hero.description')}
                        </p>

                        {/* CTA Buttons */}
                        <div className="flex flex-col sm:flex-row gap-4 pt-4">
                            <Link 
                                to="/courses" 
                                className="group relative px-8 py-4 bg-gradient-to-r from-blue-400 to-purple-500 text-white rounded-2xl font-semibold text-lg shadow-xl hover:shadow-blue-400/40 transform hover:-translate-y-1 transition-all duration-300 overflow-hidden"
                            >
                                <div className="absolute inset-0 bg-gradient-to-r from-blue-500 to-purple-600 opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
                                <div className="relative flex items-center justify-center space-x-2">
                                    <span>{t('hero.buttons.explorePrograms')}</span>
                                    <svg className="w-5 h-5 group-hover:translate-x-1 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8l4 4m0 0l-4 4m4-4H3" />
                                    </svg>
                                </div>
                            </Link>

                            <Link 
                                to="/apply" 
                                className="group px-8 py-4 border-2 border-blue-400 text-blue-600 bg-white/70 rounded-2xl font-semibold text-lg backdrop-blur-sm hover:bg-blue-50 hover:border-blue-500 hover:shadow-lg transform hover:-translate-y-1 transition-all duration-300"
                            >
                                <span className="group-hover:text-blue-700 transition-colors duration-300">
                                    {t('hero.buttons.applyNow')}
                                </span>
                            </Link>
                        </div>

                        {/* Stats */}
                        <div className="grid grid-cols-3 gap-8 pt-8 border-t-2 border-blue-200">
                            <div className="text-center group">
                                <div className="text-3xl lg:text-4xl font-bold bg-gradient-to-r from-blue-500 to-purple-500 bg-clip-text text-transparent group-hover:scale-110 transition-transform duration-300">
                                    93%
                                </div>
                                <div className="text-gray-600 text-sm mt-1 font-semibold">
                                    {t('hero.stats.jobPlacement')}
                                </div>
                            </div>

                            <div className="text-center group">
                                <div className="text-3xl lg:text-4xl font-bold bg-gradient-to-r from-purple-500 to-pink-500 bg-clip-text text-transparent group-hover:scale-110 transition-transform duration-300">
                                    50+
                                </div>
                                <div className="text-gray-600 text-sm mt-1 font-semibold">
                                    {t('hero.stats.industryPartners')}
                                </div>
                            </div>

                            <div className="text-center group">
                                <div className="text-3xl lg:text-4xl font-bold bg-gradient-to-r from-pink-500 to-blue-500 bg-clip-text text-transparent group-hover:scale-110 transition-transform duration-300">
                                    15+
                                </div>
                                <div className="text-gray-600 text-sm mt-1 font-semibold">
                                    {t('hero.stats.yearsExcellence')}
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Right Content - Image */}
                    <div className={`lg:w-1/2 mt-16 lg:mt-0 lg:pl-16 transform transition-all duration-1000 delay-300 ${isVisible ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>
                        <div className="relative group">

                            {/* Main Image Container */}
                            <div className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-blue-200/50 to-purple-200/50 backdrop-blur-sm border-2 border-white/50 shadow-2xl group-hover:shadow-blue-400/30 transition-all duration-500">

                                {/* Glow Effect */}
                                <div className="absolute -inset-0.5 bg-gradient-to-r from-blue-400 to-purple-500 rounded-3xl blur opacity-40 group-hover:opacity-60 transition-opacity duration-500"></div>

                                <div className="relative p-4">
                                    <img 
                                        src={heroImage} 
                                        alt={t('hero.imageAlt')}
                                        className="w-full h-auto rounded-2xl shadow-xl transform group-hover:scale-105 transition-transform duration-500"
                                    />

                                    {/* Image Overlay */}
                                    <div className="absolute inset-4 bg-gradient-to-t from-blue-200/30 via-transparent to-transparent rounded-2xl"></div>
                                </div>
                            </div>

                            {/* Floating Tech Tags */}
                            <div className="absolute -right-8 top-8 space-y-4">
                                <div className="flex items-center space-x-3 bg-white/80 backdrop-blur-md border-2 border-blue-200 rounded-full px-4 py-2 shadow-lg animate-bounce">
                                    <div className="w-8 h-8 bg-gradient-to-r from-blue-400 to-blue-500 rounded-full flex items-center justify-center shadow-lg">
                                        <svg className="w-4 h-4 text-white" fill="currentColor" viewBox="0 0 20 20">
                                            <path fillRule="evenodd" d="M12.316 3.051a1 1 0 01.633 1.265l-4 12a1 1 0 11-1.898-.632l4-12a1 1 0 011.265-.633zM5.707 6.293a1 1 0 010 1.414L3.414 10l2.293 2.293a1 1 0 11-1.414 1.414l-3-3a1 1 0 010-1.414l3-3a1 1 0 011.414 0zm8.586 0a1 1 0 011.414 0l3 3a1 1 0 010 1.414l-3 3a1 1 0 11-1.414-1.414L16.586 10l-2.293-2.293a1 1 0 010-1.414z" clipRule="evenodd" />
                                        </svg>
                                    </div>
                                    <span className="text-gray-700 font-semibold text-sm">
                                        {t('hero.techTags.webDevelopment')}
                                    </span>
                                </div>
                            </div>

                            <div className="absolute -left-8 top-32 space-y-4">
                                <div className="flex items-center space-x-3 bg-white/80 backdrop-blur-md border-2 border-purple-200 rounded-full px-4 py-2 shadow-lg animate-bounce" style={{animationDelay: '0.5s'}}>
                                    <div className="w-8 h-8 bg-gradient-to-r from-purple-400 to-purple-500 rounded-full flex items-center justify-center shadow-lg">
                                        <svg className="w-4 h-4 text-white" fill="currentColor" viewBox="0 0 20 20">
                                            <path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" />
                                        </svg>
                                    </div>
                                    <span className="text-gray-700 font-semibold text-sm">
                                        {t('hero.techTags.cybersecurity')}
                                    </span>
                                </div>
                            </div>

                            <div className="absolute -right-4 bottom-20 space-y-4">
                                <div className="flex items-center space-x-3 bg-white/80 backdrop-blur-md border-2 border-pink-200 rounded-full px-4 py-2 shadow-lg animate-bounce" style={{animationDelay: '1s'}}>
                                    <div className="w-8 h-8 bg-gradient-to-r from-pink-400 to-pink-500 rounded-full flex items-center justify-center shadow-lg">
                                        <svg className="w-4 h-4 text-white" fill="currentColor" viewBox="0 0 20 20">
                                            <path d="M2 10a8 8 0 018-8v8h8a8 8 0 11-16 0z" />
                                            <path d="M12 2.252A8.014 8.014 0 0117.748 8H12V2.252z" />
                                        </svg>
                                    </div>
                                    <span className="text-gray-700 font-semibold text-sm">
                                        {t('hero.techTags.dataScience')}
                                    </span>
                                </div>
                            </div>

                            <div className="absolute -left-4 bottom-8 space-y-4">
                                <div className="flex items-center space-x-3 bg-white/80 backdrop-blur-md border-2 border-green-200 rounded-full px-4 py-2 shadow-lg animate-bounce" style={{animationDelay: '1.5s'}}>
                                    <div className="w-8 h-8 bg-gradient-to-r from-green-400 to-green-500 rounded-full flex items-center justify-center shadow-lg">
                                        <svg className="w-4 h-4 text-white" fill="currentColor" viewBox="0 0 20 20">
                                            <path d="M5.5 16a3.5 3.5 0 01-.369-6.98 4 4 0 117.753-1.977A4.5 4.5 0 1113.5 16h-8z" />
                                        </svg>
                                    </div>
                                    <span className="text-gray-700 font-semibold text-sm">
                                        {t('hero.techTags.cloudComputing')}
                                    </span>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Bottom Gradient */}
            <div className="absolute bottom-0 left-0 right-0 h-32 bg-gradient-to-t from-blue-50 to-transparent"></div>
        </section>
    );
};

export default Hero;
